mapper.update:
update score_entry
usual_score = #{usualScore}, final_score = #{finalScore}, total_score = #{totalScore}, score_point = #{scorePoint}, makeup_score = #{makeupScore}, exam_status = #{examStatus},
where id = #{id}

mapper.select:
select se.id, c.course_name, s.name as studentName, s.student_no as studentNo,
       sm.name as semesterName, se.usual_score, se.final_score, se.total_score,
       se.score_point, c.credit, se.exam_status
from score_entry se
left join course c on se.course_id = c.id
left join student s on se.student_id = s.id
left join semester sm on se.semester_id = sm.id

    and se.course_id = #{courseId}
    and se.student_id = #{studentId}
    and se.semester_id = #{semesterId}

select se.id, se.student_id, s.name as studentName, s.student_no as studentNo, s.class_id, cl.class_name, m.id as majorId, m.major_name as majorName, co.id as collegeId, co.college_name as collegeName, se.course_id, c.course_name as courseName, se.usual_score, se.final_score, se.total_score from score_entry se left join student s on se.student_id = s.id left join course c on se.course_id = c.id left join class cl on s.class_id = cl.id left join major m on cl.major_id = m.id left join college co on m.college_id = co.id where se.semester_id = #{query.semesterId}
and se.student_id = #{query.studentId}
and se.course_id = #{query.courseId}
and s.class_id = #{query.classId}
and m.id = #{query.majorId}
and co.id = #{query.collegeId}
